function cancellationReason(signal) {
  return signal.reason ?? new Error("operation cancelled");
}

export class SessionPump {
  #generation = 0;
  #current = null;

  constructor({ onMessage = async () => {}, onStatus = () => {} } = {}) {
    this.onMessage = onMessage;
    this.onStatus = onStatus;
  }

  replace(transport, signal = new AbortController().signal) {
    const generation = ++this.#generation;
    this.#current = { generation, transport };
    this.onStatus({ kind: "online", name: transport.name });

    const run = (async () => {
      if (signal.aborted) {
        throw cancellationReason(signal);
      }

      await transport.open(signal);

      while (true) {
        if (signal.aborted) {
          throw cancellationReason(signal);
        }

        const message = await transport.receive(signal);
        if (message === null) {
          return;
        }
        await this.onMessage(message);
      }
    })();

    return run.finally(() => {
      this.#current = null;
      this.onStatus({ kind: "offline", name: transport.name });
    });
  }

  currentTransport() {
    return this.#current?.transport ?? null;
  }
}

