import { linkAbort } from "./abort-link.mjs";
import { SessionPump } from "./session-pump.mjs";

export class ConnectionService {
  #pump;

  constructor(callbacks = {}) {
    this.#pump = new SessionPump(callbacks);
  }

  connect(transport, parentSignal) {
    const linked = linkAbort(parentSignal);
    return this.#pump.replace(transport, linked.signal).finally(() => {
      linked.dispose();
    });
  }

  currentName() {
    return this.#pump.currentTransport()?.name ?? null;
  }
}

