import test from "node:test";
import assert from "node:assert/strict";

import { ConnectionService } from "../src/connection-service.mjs";

test("current transport delivers messages and reports orderly EOF", async () => {
  const messages = [];
  const statuses = [];
  const queue = [{ id: "ready" }, null];
  let opens = 0;
  const transport = {
    name: "primary",
    async open() {
      opens += 1;
    },
    async receive() {
      return queue.shift();
    }
  };

  const service = new ConnectionService({
    onMessage: async (message) => messages.push(message),
    onStatus: (status) => statuses.push(status)
  });

  await service.connect(transport, null);

  assert.equal(opens, 1);
  assert.deepEqual(messages, [{ id: "ready" }]);
  assert.deepEqual(statuses, [
    { kind: "online", name: "primary" },
    { kind: "offline", name: "primary" }
  ]);
  assert.equal(service.currentName(), null);
});

test("cancellation raised after connect reaches the active receive", async () => {
  const parent = new AbortController();
  const reason = new Error("operator stop");
  let opened = false;
  const transport = {
    name: "cancellable",
    async open() {
      opened = true;
    },
    receive(signal) {
      return new Promise((resolve, reject) => {
        signal.addEventListener("abort", () => reject(signal.reason), { once: true });
      });
    }
  };

  const service = new ConnectionService();
  const running = service.connect(transport, parent.signal);
  await Promise.resolve();
  parent.abort(reason);

  await assert.rejects(running, (error) => error === reason);
  assert.equal(opened, true);
});
